        BusinessPath(id: "trash-bin-cleaning", name: "Trash Bin Cleaning", icon: "trash.fill", category: .homeProperty, overview: "Clean and sanitize residential and commercial trash bins using a pressure washer and eco-friendly cleaning solution. Recurring monthly revenue from subscription customers.", startupCostRange: "$200–$500", timeToFirstDollar: "1–2 weeks", customerType: "Homeowners, HOAs, Property Managers", aiProofRating: 95, educationRequired: "None", actionPlan: ["Buy or rent a pressure washer and bin cleaning supplies", "Create a simple pricing sheet ($30–$50/month per home)", "Go door-to-door in your neighborhood offering a free first clean", "Set up recurring billing with Square or Stripe", "Expand to nearby neighborhoods and commercial accounts"], starterPricing: "$30–$50/month per residential bin, $75–$150/month commercial", outreachTemplate: "Hi [Name], I noticed your trash bins could use a deep clean. I offer a monthly bin cleaning service that eliminates odors and bacteria. Would you be interested in a free first clean?", socialMediaPost: "🗑️ Tired of smelly trash bins? I deep-clean and sanitize bins monthly so you never have to deal with the stink. DM me for a free first clean! #TrashBinCleaning #CleanBins", revenueProjections: "20 residential clients = $600–$1,000/month. Scale to 50+ clients for $1,500–$2,500/month.", draftEmail: "Subject: Fresh, Clean Bins Every Month\n\nHi [Name],\n\nI'm [Your Name], and I run a local trash bin cleaning service. Each month, I deep-clean and sanitize your bins using eco-friendly products, eliminating odors and harmful bacteria.\n\nI'm offering a free first clean to new customers in your area. No commitment required.\n\nWould you like to schedule yours this week?\n\nBest,\n[Your Name]", draftTextMessage: "Hey [Name]! I'm offering free trash bin cleanings this week in your neighborhood. Want me to add you to the schedule? No strings attached 🗑️✨", salesIntroScript: "Hi, I'm [Your Name]. I run a local bin cleanin